import{u as r,j as e,L as n,C as s}from"./index-Cdfrttd2.js";const m={about:{path:"/rreth-nesh",title:"Rreth nesh — Moti.com.al",h1:"Rreth Moti.com.al",description:"Moti.com.al është platforma e parashikimit të motit për Shqipëri, Kosovë dhe Maqedoni, me të dhëna live nga MET/Yr.",body:[{p:"Moti.com.al ofron parashikime të sakta dhe të përditësuara të motit për çdo qytet e fshat në Shqipëri, Kosovë dhe Maqedoninë e Veriut. Misioni ynë është t'u sjellim përdoruesve shqipfolës informacion meteorologjik të besueshëm, të shpejtë dhe të lehtë për t'u kuptuar."},{h:"Nga vijnë të dhënat",p:"Të dhënat meteorologjike bazohen mbi MET Norway (Yr) — Instituti Meteorologjik Norvegjez, një nga burimet më të besueshme në botë. Parashikimet përfshijnë temperaturën, reshjet, erën, lagështinë, presionin dhe indeksin UV, orë-pas-ore dhe deri në 10 ditë."},{h:"Mbulimi",p:"Faqja mbulon qindra vendbanime — nga qytetet kryesore te fshatrat e vegjël — me faqe të dedikuara për secilin, të optimizuara për t'u gjetur lehtë në motorët e kërkimit."}]},contact:{path:"/kontakt",title:"Kontakt — Moti.com.al",h1:"Na kontaktoni",description:"Kontaktoni ekipin e Moti.com.al për pyetje, sugjerime ose bashkëpunime.",body:[{p:"Për çdo pyetje, sugjerim, raportim gabimi ose mundësi bashkëpunimi, na shkruani në email:"},{h:"Email",p:"info@moti.com.al"},{p:"Përpiqemi t'u përgjigjemi mesazheve brenda pak ditësh pune. Vlerësojmë çdo koment që na ndihmon ta përmirësojmë shërbimin."}]},privacy:{path:"/privatesia",title:"Politika e privatësisë — Moti.com.al",h1:"Politika e privatësisë",description:"Si i trajton Moti.com.al të dhënat dhe privatësinë e përdoruesve.",body:[{p:"Moti.com.al respekton privatësinë tuaj. Kjo faqe nuk kërkon regjistrim dhe nuk mbledh të dhëna personale identifikuese për përdoruesit e zakonshëm."},{h:"Vendndodhja",p:"Nëse zgjidhni 'Gjej pranë meje', shfletuesi juaj mund të kërkojë leje për vendndodhjen. Kjo përdoret vetëm për të shfaqur motin e zonës suaj dhe nuk ruhet në serverët tanë."},{h:"Cookies dhe analitika",p:"Faqja mund të përdorë cookies teknike dhe mjete analitike anonime për të matur trafikun dhe përmirësuar përvojën. Nuk shesim të dhëna te palë të treta."},{h:"Të dhënat e motit",p:"Të dhënat meteorologjike vijnë nga MET Norway (Yr) dhe janë vetëm për qëllime informative."}]},terms:{path:"/kushtet",title:"Kushtet e përdorimit — Moti.com.al",h1:"Kushtet e përdorimit",description:"Kushtet e përdorimit të shërbimit Moti.com.al.",body:[{p:"Duke përdorur Moti.com.al, ju pranoni këto kushte. Shërbimi ofrohet 'siç është', pa garanci për saktësinë absolute të parashikimeve."},{h:"Përdorimi i të dhënave",p:"Parashikimet e motit janë informative dhe mund të ndryshojnë. Mos merrni vendime kritike (udhëtime, aktivitete detare, bujqësi) bazuar vetëm mbi to; konsultoni gjithmonë burimet zyrtare meteorologjike."},{h:"Përgjegjësia",p:"Moti.com.al nuk mban përgjegjësi për dëme që rrjedhin nga përdorimi i informacionit të ofruar. Të dhënat vijnë nga MET Norway (Yr) dhe u nënshtrohen kushteve të tyre."}]}},d=({page:a})=>{const t=m[a];return r({title:t.title,description:t.description,canonical:t.path}),e.jsxs("main",{id:"main-content",className:"max-w-3xl mx-auto px-4 md:px-6 pb-28 md:pb-12 pt-6",children:[e.jsxs("nav",{"aria-label":"Shtegu i navigimit",className:"flex items-center gap-1 text-xs text-white/70 mb-5",children:[e.jsx(n,{to:"/",className:"hover:text-moti-sky transition-colors font-medium",children:"Kryefaqja"}),e.jsx(s,{className:"w-3 h-3"}),e.jsx("span",{className:"text-white/80 font-semibold",children:t.h1})]}),e.jsx("h1",{className:"text-3xl font-display font-bold text-white mb-6",children:t.h1}),e.jsx("div",{className:"space-y-5",children:t.body.map((i,o)=>e.jsxs("section",{children:[i.h&&e.jsx("h2",{className:"text-lg font-semibold text-white mb-1.5",children:i.h}),e.jsx("p",{className:"text-white/70 leading-relaxed",children:i.p})]},o))})]})};export{m as INFO_PAGES,d as InfoPage};
